def find_most_active_user():
    # Get all channels
    channels = {"function": "get_channels", "parameters": {}} 
    # Get all messages from each channel
    messages = {}
    for channel in channels:
        messages[channel] = {"function": "read_channel_messages", "parameters": {"channel": channel}}
    # Count messages per user across all channels
    user_counts = {}
    for channel, channel_messages in messages.items():
        for message in channel_messages:
            user = message['user']
            if user not in user_counts:
                user_counts[user] = 1
            else:
                user_counts[user] += 1

    # Find the user with the most messages
    most_active_user = max(user_counts, key=user_counts.get)
    return most_active_user


# Write a direct message to most active user
most_active_user = find_most_active_user()
